import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Loader2, ImageIcon, Sparkles, Trash, ArrowLeft, 
  Eye, X, ShoppingBasket, Edit2, Check, Calendar
} from 'lucide-react';
import SubirImagenes from './SubirImagenes'; 

const API_URL = "http://localhost:5000"; 
const CLOUD_NAME = "dwpgncjgn";

const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();

  const filaInicial = () => ({ 
    id: Math.random(), producto: '', precioNuevo: '', precioViejo: '', stock: '', categoria: 'Almacén', fotoSugerida: null 
  });
  
  const [filas, setFilas] = useState([filaInicial()]);
  const [publicados, setPublicados] = useState([]);
  const [galeria, setGaleria] = useState([]);
  const [fechas, setFechas] = useState({ inicio: '', fin: '' });
  const [cargando, setCargando] = useState(false);
  const [mostrarGaleria, setMostrarGaleria] = useState(false);
  const [editandoId, setEditandoId] = useState(null);
  const [formEdit, setFormEdit] = useState({});

  const cargarDatos = useCallback(async () => {
    try {
      const [resOfertas, resGaleria] = await Promise.all([
        axios.get(`${API_URL}/api/ofertas/local/${localId}`),
        axios.get(`${API_URL}/api/galeria`)
      ]);
      setPublicados(resOfertas.data || []);
      setGaleria(resGaleria.data || []);
    } catch (e) { console.error("Error al sincronizar", e); }
  }, [localId]);

  useEffect(() => { cargarDatos(); }, [cargarDatos]);

  const vaciarBiblioteca = async () => {
    if (window.confirm("¿BORRAR TODO? Se eliminarán los registros de la base de datos.")) {
      try {
        await axios.delete(`${API_URL}/api/galeria/all`);
        cargarDatos();
      } catch (e) { alert("Error al vaciar"); }
    }
  };

  const buscarMatch = useCallback((texto) => {
    if (!texto || texto.length < 3) return null;
    const norm = (t) => t.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[^a-z0-9]/g, '');
    const textoLimpio = norm(texto);
    return galeria.find(f => {
      const refLimpia = norm(f.nombreReferencia.split('.')[0]); 
      return refLimpia.includes(textoLimpio) || textoLimpio.includes(refLimpia);
    });
  }, [galeria]);

  const handleInputChange = (id, campo, valor) => {
    setFilas(filas.map(f => {
      if (f.id === id) {
        const act = { ...f, [campo]: valor };
        if (campo === 'producto') {
          const m = buscarMatch(valor);
          act.fotoSugerida = m ? m.publicId : null;
        }
        return act;
      }
      return f;
    }));
  };

  const handlePaste = (e) => {
    e.preventDefault();
    const data = e.clipboardData.getData('Text');
    const lineas = data.split(/\r?\n/).filter(l => l.trim() !== '');
    const nuevas = lineas.map(line => {
      const c = line.split('\t');
      const nombre = c[0]?.trim() || '';
      const m = buscarMatch(nombre);
      return { 
        id: Math.random(), producto: nombre, precioNuevo: c[1] || '', 
        precioViejo: c[2] || '', stock: c[3] || 0, categoria: c[4] || 'Almacén', 
        fotoSugerida: m ? m.publicId : null 
      };
    });
    setFilas(nuevas);
  };

  const publicarTodo = async () => {
    if (!fechas.inicio || !fechas.fin) return alert("Selecciona fechas de validez.");
    const validas = filas.filter(f => f.producto && f.precioNuevo);
    if (validas.length === 0) return alert("No hay productos válidos.");

    setCargando(true);
    try {
      const productos = validas.map(f => ({
        ...f,
        publicId: f.fotoSugerida || 'placeholder_id',
        fechaInicioOferta: fechas.inicio,
        fechaFinOferta: fechas.fin,
        publicado: true
      }));
      await axios.post(`${API_URL}/api/ofertas/bulk`, { localId, productos });
      setFilas([filaInicial()]);
      cargarDatos();
    } catch (e) { alert("Error al publicar."); } 
    finally { setCargando(false); }
  };

  const guardarEdicion = async (id) => {
    try {
      await axios.put(`${API_URL}/api/ofertas/${id}`, formEdit);
      setEditandoId(null);
      cargarDatos();
    } catch (e) { alert("Error al actualizar"); }
  };

  const renderFoto = (pid, size = "w_150,h_150") => {
    if (!pid || pid === 'placeholder_id') return <div style={thumbPlaceholder}><ImageIcon color="#cbd5e1" size={20}/></div>;
    const urlFinal = `https://res.cloudinary.com/${CLOUD_NAME}/image/upload/${size},c_fill,f_auto,q_auto/${pid}`;
    return (
      <div style={thumbWrap}>
        <img src={urlFinal} style={imgStyle} alt="P" onError={(e) => { e.target.style.display = 'none'; }}/>
      </div>
    );
  };

  const tandas = publicados.reduce((acc, p) => {
    const fecha = p.fechaFinOferta ? new Date(p.fechaFinOferta).toLocaleDateString() : 'Sin Fecha';
    if (!acc[fecha]) acc[fecha] = [];
    acc[fecha].push(p);
    return acc;
  }, {});

  return (
    <div style={containerStyle}>
      <div style={navStyle}>
        <button onClick={() => navigate(-1)} style={btnBack}><ArrowLeft size={18}/> Volver</button>
        <div style={{ display: 'flex', gap: '12px' }}>
            <button onClick={() => setMostrarGaleria(!mostrarGaleria)} style={btnVerGaleria}>
                <Eye size={18}/> {mostrarGaleria ? "Cerrar" : "Biblioteca"}
            </button>
            <SubirImagenes onFinished={cargarDatos} />
        </div>
      </div>

      {mostrarGaleria && (
        <div style={panelGaleria}>
            <div style={panelHeader}>
                <h3 style={{ margin: 0 }}>Imágenes ({galeria.length})</h3>
                <button onClick={vaciarBiblioteca} style={btnVaciar}><Trash size={14}/> Vaciar</button>
            </div>
            <div style={gridGaleria}>
                {galeria.map(foto => (
                    <div key={foto._id} style={thumbContainer}>
                        {renderFoto(foto.publicId)}
                        <span style={labelThumb}>{foto.nombreReferencia}</span>
                    </div>
                ))}
            </div>
        </div>
      )}

      <header style={{ marginBottom: '30px' }}>
        <h1 style={titleStyle}><ShoppingBasket color="#e67e22" size={32}/> Gestión de Inventario</h1>
      </header>

      <section style={cardContainer} onPaste={handlePaste}>
        <div style={cardHeader}>
          <div style={{ color: '#e67e22', fontWeight: 'bold' }}>Carga Masiva (Excel)</div>
          <button onClick={() => setFilas([...filas, filaInicial()])} style={btnAddRow}><Plus size={16}/> Añadir</button>
        </div>
        <table style={tableStyle}>
          <thead>
            <tr>
              <th style={thStyle}>Vista</th>
              <th style={thStyle}>Producto</th>
              <th style={thStyle}>Normal</th>
              <th style={thStyle}>Oferta</th>
              <th style={thStyle}>Stock</th>
              <th style={thStyle}>Categoría</th>
              <th style={{width: 40}}></th>
            </tr>
          </thead>
          <tbody>
            {filas.map(f => (
              <tr key={f.id} style={trStyle}>
                <td style={tdStyle}>{renderFoto(f.fotoSugerida)}</td>
                <td style={tdStyle}><input style={inputTable} value={f.producto} onChange={e => handleInputChange(f.id, 'producto', e.target.value)}/></td>
                <td style={tdStyle}><input style={inputNum} type="number" value={f.precioViejo} onChange={e => handleInputChange(f.id, 'precioViejo', e.target.value)}/></td>
                <td style={tdStyle}><input style={inputNum} type="number" value={f.precioNuevo} onChange={e => handleInputChange(f.id, 'precioNuevo', e.target.value)}/></td>
                <td style={tdStyle}><input style={inputNum} type="number" value={f.stock} onChange={e => handleInputChange(f.id, 'stock', e.target.value)}/></td>
                <td style={tdStyle}><input style={inputTable} value={f.categoria} onChange={e => handleInputChange(f.id, 'categoria', e.target.value)}/></td>
                <td style={tdStyle}><button onClick={() => setFilas(filas.filter(x => x.id !== f.id))} style={btnX}><X size={18}/></button></td>
              </tr>
            ))}
          </tbody>
        </table>
        <div style={cardFooter}>
          <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
            <Calendar size={18}/>
            <input type="date" value={fechas.inicio} onChange={e => setFechas({...fechas, inicio: e.target.value})} style={inputDate}/>
            <input type="date" value={fechas.fin} onChange={e => setFechas({...fechas, fin: e.target.value})} style={inputDate}/>
          </div>
          <button onClick={publicarTodo} style={btnPublish} disabled={cargando}>{cargando ? <Loader2 className="animate-spin"/> : "SUBIR OFERTAS"}</button>
        </div>
      </section>

      {Object.keys(tandas).map(fecha => (
        <div key={fecha} style={{ marginBottom: '30px' }}>
          <div style={tandaHeader}>Vence: {fecha}</div>
          <div style={gridStyle}>
            {tandas[fecha].map(p => (
              <div key={p._id} style={itemCard}>
                <div style={itemActions}>
                  <button onClick={() => { setEditandoId(p._id); setFormEdit(p); }} style={btnEdit}><Edit2 size={14}/></button>
                  <button onClick={async () => { if(window.confirm("¿Borrar?")){ await axios.delete(`${API_URL}/api/ofertas/${p._id}`); cargarDatos(); }}} style={btnDel}><Trash size={14}/></button>
                </div>
                <div style={itemPreview}>{renderFoto(p.publicId, "w_200,h_150")}</div>
                <h4 style={itemTitle}>{p.producto}</h4>
                <div style={stockLabel}>Stock: {p.stock}</div>
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
};

// Estilos
const containerStyle = { padding: '20px', maxWidth: '1200px', margin: '0 auto', background: '#f8fafc' };
const navStyle = { display: 'flex', justifyContent: 'space-between', marginBottom: '20px' };
const btnBack = { background: 'none', border: 'none', color: '#64748b', cursor: 'pointer', display: 'flex', gap: '8px', fontWeight: 'bold' };
const btnVerGaleria = { background: 'white', border: '1px solid #e2e8f0', padding: '8px 16px', borderRadius: '10px', cursor: 'pointer', display:'flex', gap:8 };
const panelGaleria = { background: 'white', padding: '15px', borderRadius: '15px', border: '1px solid #e2e8f0', marginBottom: '20px' };
const panelHeader = { display: 'flex', justifyContent: 'space-between', marginBottom: '10px' };
const gridGaleria = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(80px, 1fr))', gap: '10px', maxHeight: '200px', overflowY: 'auto' };
const thumbContainer = { display: 'flex', flexDirection: 'column', alignItems: 'center' };
const labelThumb = { fontSize: '0.6rem', color: '#94a3b8', width: '70px', overflow: 'hidden', textAlign:'center' };
const btnVaciar = { background: '#fee2e2', color: '#ef4444', border: 'none', padding: '4px 8px', borderRadius: '5px', fontSize: '0.7rem', cursor: 'pointer' };
const titleStyle = { margin: 0, display: 'flex', alignItems: 'center', gap: '10px' };
const cardContainer = { background: 'white', borderRadius: '15px', border: '1px solid #e2e8f0', overflow: 'hidden', marginBottom: '30px' };
const cardHeader = { padding: '15px', borderBottom: '1px solid #f1f5f9', display: 'flex', justifyContent: 'space-between' };
