const inputTable = { width: '100%', border: 'none', outline: 'none', fontSize: '0.85rem' };
const inputNum = { width: '60px', padding: '4px', border: '1px solid #e2e8f0', borderRadius: '4px' };
const cardFooter = { padding: '15px', display: 'flex', justifyContent: 'space-between', background: '#f8fafc' };
const inputDate = { padding: '5px', borderRadius: '5px', border: '1px solid #e2e8f0', fontSize: '0.75rem' };
const btnPublish = { background: '#e67e22', color: 'white', border: 'none', padding: '10px 20px', borderRadius: '10px', cursor: 'pointer', fontWeight: 'bold' };
const tandaHeader = { background: '#1e293b', color: 'white', padding: '5px 15px', borderRadius: '5px', marginBottom: '15px', display: 'inline-block', fontSize: '0.8rem' };
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '20px' };
const itemCard = { background: 'white', padding: '15px', borderRadius: '15px', border: '1px solid #e2e8f0', position: 'relative' };
const itemActions = { position: 'absolute', top: 10, right: 10, display: 'flex', gap: 5 };
const btnEdit = { background: '#f1f5f9', border: 'none', borderRadius: '50%', padding: '5px', cursor: 'pointer' };
const btnDel = { background: '#fee2e2', border: 'none', borderRadius: '50%', padding: '5px', cursor: 'pointer', color: '#ef4444' };
const itemPreview = { height: '100px', display: 'flex', justifyContent: 'center', alignItems: 'center' };
const itemTitle = { fontSize: '0.9rem', textAlign: 'center', margin: '10px 0' };
const stockLabel = { textAlign: 'center', fontSize: '0.75rem', color: '#64748b' };
const thumbWrap = { width: 45, height: 45, borderRadius: 5, overflow: 'hidden' };
const imgStyle = { width: '100%', height: '100%', objectFit: 'cover' };
const thumbPlaceholder = { width: 45, height: 45, background: '#f1f5f9', borderRadius: 5, display: 'flex', alignItems: 'center', justifyContent: 'center' };
